+/// Render one block per comparison for human debugging. This intentionally
+/// stays separate from [`render_agent_eval_human`], which is optimized for the
+/// grouped Main/Cost report.
+pub fn render_agent_eval_human_debug(report: &AgentEvalReport) -> String {
+    let mut lines = Vec::new();
+    lines.push(format!(
+        "Valid comparisons: {}/{}",
+        report.summary.valid_pairs, report.summary.total_pairs
+    ));
+
+    for row in &report.comparisons {
+        lines.push(String::new());
+        lines.push(format!("Comparison: {}", row.task_id));
+        lines.push(format!("  task: {}", row.task));
+        lines.push(format!("  result: {}", row.result.slug()));
+        lines.push(format!(
+            "  valid: {}",
+            if row.valid_for_comparison {
+                "yes"
+            } else {
+                "no"
+            }
+        ));
+        if let Some(reason) = &row.excluded_reason {
+            lines.push(format!("  excluded_reason: {reason}"));
+        }
+        push_run_debug_lines(&mut lines, AgentArm::Vanilla, &row.vanilla);
+        push_run_debug_lines(&mut lines, row.treatment_arm, &row.treatment);
+    }
+
+    lines.join("\n")
+}
+
+fn push_run_debug_lines(lines: &mut Vec<String>, arm: AgentArm, score: &AgentRunScore) {
+    let label = arm.display_label();
+    let target_files = ratio_cell(score.target_files_hit, score.target_files_total);
+    let tests_passed = score.tests_passed;
+    let turns = option_cell(score.turn_count);
+    let tokens = option_cell(score.tokens_total);
+    lines.push(format!(
+        "  {label}: target_files={target_files} tests_passed={tests_passed} turns={turns} tokens={tokens}"
+    ));
+    let discover = debug_option_cell(score.discover_command_count);
+    let read = debug_option_cell(score.file_read_count);
+    let edit = debug_option_cell(score.edit_command_count);
+    let verify = debug_option_cell(score.verify_command_count);
+    lines.push(format!(
+        "  shell_phases: discover={discover} read={read} edit={edit} verify={verify}"
+    ));
+}
